import hashlib
import os
import secrets
from dataclasses import dataclass
from typing import Optional

SHARED_SECRET_KEY = "telescope_web_secret"


@dataclass
class User:
    phone_id: str
    name: str
    role: str  # "admin" or "viewer"


_ADMINS: list[User] = [
    User(phone_id="[REDACTED_PHONE]", name="Bram", role="admin"),
    User(phone_id="[REDACTED_PHONE]", name="Admin2", role="admin"),
]


def _token_hash(token: str) -> str:
    return hashlib.sha256(token.encode()).hexdigest()


def _generate_token(secret: str, phone_id: str) -> str:
    raw = f"{secret}:{phone_id}:{secrets.token_hex(8)}"
    return _token_hash(raw)


def _validate_token(token: str, secret: str, phone_id: str, stored: str) -> bool:
    return _token_hash(f"{secret}:{phone_id}:{token}") == stored


class AuthManager:
    """Simple in-memory token-based auth.

    Users authenticate with a shared secret (e.g. set in config or env var).
    On first access they enter the secret to get a session token.
    """

    def __init__(self, secret: str = "telescope"):
        self._secret = secret
        # phone_id -> token hash
        self._tokens: dict[str, str] = {}
        # phone_id -> user
        self._users: dict[str, User] = {u.phone_id: u for u in _ADMINS}

    def is_admin(self, phone_id: str) -> bool:
        user = self._users.get(phone_id)
        return user is not None and user.role == "admin"

    def authenticate(self, phone_id: str, secret: str) -> Optional[str]:
        if secret != self._secret:
            return None
        token = secrets.token_urlsafe(32)
        self._tokens[phone_id] = _token_hash(token)
        return token

    def validate_session(self, phone_id: str, token: str) -> bool:
        stored = self._tokens.get(phone_id)
        if not stored:
            return False
        return _token_hash(token) == stored

    def get_user(self, phone_id: str) -> Optional[User]:
        return self._users.get(phone_id)

    def add_admin(self, phone_id: str, name: str = ""):
        if phone_id not in self._users:
            self._users[phone_id] = User(phone_id=phone_id, name=name or phone_id, role="admin")
