import logging
import socket
from datetime import datetime, timezone
from http.server import BaseHTTPRequestHandler, ThreadingHTTPServer
from typing import Any, Dict, List, Optional
from urllib.parse import parse_qs, urlparse

from .auth import AuthManager, User
from .classifier import ObjectClassifier
from .config import TelescopeConfig
from .events import SkyEventsService
from .mount import MountController
from .scheduler import NightScheduler
from .weather import WeatherService

logger = logging.getLogger(__name__)


def _best_lan_ip() -> str:
    """Best-effort LAN IP detection for phone access."""
    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    try:
        sock.connect(("8.8.8.8", 80))
        return sock.getsockname()[0]
    except OSError:
        return "127.0.0.1"
    finally:
        sock.close()


class DashboardService:
    def __init__(self, config: TelescopeConfig):
        self.config = config
        self.mount = MountController(config)
        self.weather = WeatherService(config)
        self.classifier = ObjectClassifier(config)
        self.scheduler = NightScheduler(config, self.weather)
        self.events = SkyEventsService()

    def _safe_mount_data(self) -> Dict[str, Any]:
        if not self.mount.connected:
            self.mount.connect()

        if not self.mount.connected:
            return {"connected": False}

        ra, dec = self.mount.get_position_radec()
        alt, az = self.mount.get_position_altaz()
        classification = self.classifier.classify(ra=ra, dec=dec)
        return {
            "connected": True,
            "ra_hours": round(ra, 4),
            "dec_degrees": round(dec, 4),
            "alt_degrees": round(alt, 2),
            "az_degrees": round(az, 2),
            "object_label": classification.label,
            "object_type": classification.object_type,
            "object_confidence": round(classification.confidence, 3),
            "object_description": classification.description,
        }

    def status(self) -> Dict[str, Any]:
        weather = self.weather.get_conditions()
        mount_data = self._safe_mount_data()
        wiki_url = self._wiki_url_for_label(mount_data.get("object_label", ""))
        if wiki_url:
            mount_data["object_wiki_url"] = wiki_url
        location = {
            "latitude": round(self.config.latitude, 6),
            "longitude": round(self.config.longitude, 6),
            "elevation_m": round(self.config.elevation_m, 1),
            "maps_url": f"https://www.google.com/maps?q={self.config.latitude},{self.config.longitude}",
        }
        return {
            "timestamp_utc": datetime.now(timezone.utc).isoformat(),
            "mount_type": self.config.mount_type,
            "location": location,
            "mount": mount_data,
            "weather": {
                "condition": weather.condition,
                "cloud_cover_pct": round(weather.cloud_cover_pct, 1),
                "temperature_c": round(weather.temperature_c, 1),
                "wind_speed_ms": round(weather.wind_speed_ms, 1),
                "humidity_pct": round(weather.humidity_pct, 1),
                "is_dark": weather.is_dark,
                "is_observable": weather.is_observable,
                "reason": weather.reason,
            },
        }

    def plan(self, max_targets: int = 5) -> List[Dict[str, Any]]:
        items = self.scheduler.generate_plan(max_targets=max_targets)
        return [
            {
                "priority": item.priority,
                "name": item.target.name,
                "type": item.target.object_type,
                "altitude": item.altitude,
                "duration_minutes": item.duration_minutes,
                "reason": item.reason,
            }
            for item in items
        ]

    def forecast(self, days: int = 14) -> List[Dict[str, Any]]:
        return self.weather.get_forecast_days(days=days)

    def expected_events(self, days: int = 30) -> Dict[str, Any]:
        return {
            "upcoming": self.events.upcoming_events(days_ahead=days),
            "resources": self.events.guidance_links(),
        }

    def forecast_links(self) -> List[Dict[str, str]]:
        lat = self.config.latitude
        lon = self.config.longitude
        return [
            {
                "title": "Open-Meteo (this location)",
                "url": f"https://open-meteo.com/en/docs?latitude={lat}&longitude={lon}",
            },
            {
                "title": "Windy (clouds/radar)",
                "url": f"https://www.windy.com/{lat}/{lon}",
            },
            {
                "title": "Clear Outside (astronomy forecast)",
                "url": "https://clearoutside.com/forecast",
            },
        ]

    @staticmethod
    def _wiki_url_for_label(label: str) -> Optional[str]:
        if not label:
            return None
        lowered = label.lower()
        if lowered in {"no data provided", "unknown"} or lowered.startswith("unidentified at "):
            return None
        known = {
            "M42": "Orion_Nebula",
            "M31": "Andromeda_Galaxy",
            "M45": "Pleiades",
            "M13": "Messier_13",
            "NGC 5139": "Omega_Centauri",
            "NGC 104": "47_Tucanae",
            "LMC": "Large_Magellanic_Cloud",
            "SMC": "Small_Magellanic_Cloud",
            "NGC 3372": "Carina_Nebula",
            "NGC 2070": "Tarantula_Nebula",
            "NGC 4755": "Jewel_Box_(star_cluster)",
        }
        page = known.get(label, label.replace(" ", "_"))
        return f"https://en.wikipedia.org/wiki/{page}"


def _html_page(refresh_seconds: int) -> str:
    return f"""<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width,initial-scale=1" />
  <title>Telescope Live View</title>
  <style>
    body {{ font-family: Arial, sans-serif; margin: 18px; max-width: 900px; }}
    .card {{ border: 1px solid #ddd; border-radius: 10px; padding: 14px; margin-bottom: 14px; }}
    h1 {{ margin-top: 0; }}
    .muted {{ color: #666; font-size: 0.92rem; }}
    code {{ background: #f5f5f5; padding: 2px 5px; border-radius: 5px; }}
    ul {{ margin-top: 8px; }}
    .btn {{ display: inline-block; padding: 10px 18px; background: #007bff; color: #fff; text-decoration: none; border-radius: 6px; font-size: 1rem; }}
    .btn-danger {{ background: #dc3545; }}
    input {{ padding: 8px; font-size: 1rem; width: 100%%; max-width: 300px; box-sizing: border-box; }}
    .login-box {{ text-align: center; padding: 60px 20px; }}
    .login-box h2 {{ margin-bottom: 20px; }}
    .err {{ color: #dc3545; margin-top: 10px; }}
    .user-info {{ float: right; font-size: 0.9rem; }}
    .user-info a {{ margin-left: 12px; }}
  </style>
</head>
<body>
  <div class="user-info" id="userInfo"></div>
  <div id="loginScreen" class="login-box" style="display:none">
    <h2>Telescope Access</h2>
    <p>Enter the shared password to access the dashboard.</p>
    <input type="password" id="secretInput" placeholder="password" autocomplete="off" />
    <br/><br/>
    <button class="btn" onclick="login()">Access Dashboard</button>
    <div id="loginError" class="err"></div>
  </div>
  <div id="dashboard">
    <h1>Telescope Live View</h1>
    <p class="muted">Auto-refresh every {refresh_seconds}s</p>

    <div class="card">
      <h3>Current Pointing</h3>
      <div id="pointing">Loading...</div>
    </div>

    <div class="card">
      <h3>Current GPS Coordinates</h3>
      <div id="location">Loading...</div>
    </div>

    <div class="card">
      <h3>What You Are Seeing</h3>
      <div id="object">Loading...</div>
    </div>

    <div class="card">
      <h3>Weather</h3>
      <div id="weather">Loading...</div>
    </div>

    <div class="card">
      <h3>14-Day Forecast</h3>
      <div id="forecast">Loading...</div>
      <div id="forecast-links" class="muted"></div>
    </div>

    <div class="card">
      <h3>Tonight Plan</h3>
      <div id="plan">Loading...</div>
    </div>

    <div class="card">
      <h3>What to Expect (Sky Events)</h3>
      <div id="events">Loading...</div>
    </div>
  </div>

  <script>
    const PHONE_ID = localStorage.getItem('phone_id') || '';
    let sessionToken = localStorage.getItem('session_token') || '';

    function showLogin() {{
      document.getElementById('loginScreen').style.display = 'block';
      document.getElementById('dashboard').style.display = 'none';
    }}

    function showDashboard(user) {{
      document.getElementById('loginScreen').style.display = 'none';
      document.getElementById('dashboard').style.display = 'block';
      if (user) {{
        document.getElementById('userInfo').innerHTML =
          (user.role === 'admin' ? ' Admin' : ' Viewer') +
          ' <a href="#" onclick="logout();return false">Logout</a>';
      }}
    }}

    function logout() {{
      sessionToken = '';
      localStorage.removeItem('session_token');
      showLogin();
    }}

    async function login() {{
      const secret = document.getElementById('secretInput').value;
      document.getElementById('loginError').textContent = '';
      let pid = PHONE_ID;
      if (!pid) {{
        pid = 'phone-' + Math.random().toString(36).slice(2, 10);
        localStorage.setItem('phone_id', pid);
      }}
      try {{
        const r = await fetch('/api/auth/login', {{
          method: 'POST',
          headers: {{'Content-Type': 'application/json'}},
          body: JSON.stringify({{phone_id: pid, secret}})
        }});
        const d = await r.json();
        if (d.token) {{
          sessionToken = d.token;
          localStorage.setItem('session_token', sessionToken);
          showDashboard(d.user || null);
          refreshStatus();
        }} else {{
          document.getElementById('loginError').textContent = 'Wrong password';
        }}
      }} catch(e) {{
        document.getElementById('loginError').textContent = 'Connection error';
      }}
    }}

    async function checkSession() {{
      if (!sessionToken) {{ showLogin(); return false; }}
      try {{
        const r = await fetch('/api/auth/check?phone_id=' + encodeURIComponent(PHONE_ID) + '&token=' + encodeURIComponent(sessionToken));
        const d = await r.json();
        if (d.valid && d.user) {{
          showDashboard(d.user);
          return true;
        }}
      }} catch(e) {{}}
      showLogin();
      return false;
    }}

    async function refreshStatus() {{
      const ok = await checkSession();
      if (!ok) return;

      const s = await fetch('/api/status').then(r => r.json());
      const p = await fetch('/api/plan?max=5').then(r => r.json());
      const f = await fetch('/api/forecast?days=14').then(r => r.json());
      const fl = await fetch('/api/forecast-links').then(r => r.json());
      const e = await fetch('/api/events?days=30').then(r => r.json());

      const m = s.mount || {{}};
      const loc = s.location || {{}};
      document.getElementById('pointing').innerHTML =
        m.connected
          ? `RA: <code>${{m.ra_hours}}h</code> | Dec: <code>${{m.dec_degrees}}°</code><br/>
             Alt: <code>${{m.alt_degrees}}°</code> | Az: <code>${{m.az_degrees}}°</code>`
          : 'Mount not connected';
      document.getElementById('location').innerHTML =
        `Lat: <code>${{loc.latitude}}</code> | Lon: <code>${{loc.longitude}}</code> | Elev: <code>${{loc.elevation_m}}m</code><br/>
         ${{loc.maps_url ? `<a href="${{loc.maps_url}}" target="_blank" rel="noopener">Open in Google Maps</a>` : ''}}`;

      document.getElementById('object').innerHTML =
        m.connected
          ? `<b>${{m.object_label}}</b> (${{m.object_type}}, conf=${{Math.round((m.object_confidence || 0)*100)}}%)<br/>
             ${{m.object_wiki_url ? `<a href="${{m.object_wiki_url}}" target="_blank" rel="noopener">Open Wikipedia page</a><br/>` : ''}}
             <span class="muted">${{m.object_description || ''}}</span>`
          : 'No classification available';

      const w = s.weather || {{}};
      document.getElementById('weather').innerHTML =
        `${{w.condition}} | clouds: ${{w.cloud_cover_pct}}% | wind: ${{w.wind_speed_ms}} m/s<br/>
         dark: ${{w.is_dark}} | observable: ${{w.is_observable}}<br/>
         <span class="muted">${{w.reason || ''}}</span>`;

      const forecastItems = (f.forecast || []).map(d =>
        `<li><b>${{d.date}}</b> - ${{d.condition}} | min ${{d.temp_min_c}}°C / max ${{d.temp_max_c}}°C | clouds ${{d.cloud_cover_pct}}% | wind ${{d.wind_kph_max}} km/h</li>`
      );
      document.getElementById('forecast').innerHTML = forecastItems.length ? `<ul>${{forecastItems.join('')}}</ul>` : 'No forecast data';
      const forecastLinks = (fl.links || []).map(x =>
        `<li><a href="${{x.url}}" target="_blank" rel="noopener">${{x.title}}</a></li>`
      );
      document.getElementById('forecast-links').innerHTML = forecastLinks.length ? `<b>Forecast links</b><ul>${{forecastLinks.join('')}}</ul>` : '';

      const items = (p.plan || []).map(i =>
        `<li><b>#${{i.priority}} ${{i.name}}</b> (${{i.type}}), alt ${{i.altitude}}°, ${{i.duration_minutes}} min<br/>
         <span class="muted">${{i.reason}}</span></li>`
      );
      document.getElementById('plan').innerHTML = items.length ? `<ul>${{items.join('')}}</ul>` : 'No plan available';

      const upcoming = (e.upcoming || []).map(x =>
        `<li><b>${{x.name}}</b> (peak: ${{x.peak_date}}, in ${{x.days_until_peak}} days, ZHR ~${{x.zhr}})<br/>
         Active: ${{x.active_start}} to ${{x.active_end}}<br/>
         <span class="muted">${{x.notes}}</span></li>`
      );
      const resources = (e.resources || []).map(r =>
        `<li><a href="${{r.url}}" target="_blank" rel="noopener">${{r.title}}</a><br/>
         <span class="muted">${{r.description}}</span></li>`
      );
      document.getElementById('events').innerHTML =
        `<b>Meteor showers (next 30 days)</b>${{upcoming.length ? `<ul>${{upcoming.join('')}}</ul>` : '<p>None in selected window.</p>'}}` +
        `<b>Conjunction calendars</b>${{resources.length ? `<ul>${{resources.join('')}}</ul>` : ''}}`;
    }}

    checkSession().then(ok => {{ if (ok) refreshStatus(); }});
    setInterval(refreshStatus, {refresh_seconds} * 1000);
  </script>
</body>
</html>
"""


def run_dashboard(config: TelescopeConfig, host: str = "0.0.0.0", port: int = 8765, refresh_seconds: int = 5,
                  web_secret: str = "telescope"):
    service = DashboardService(config)
    auth = AuthManager(secret=web_secret)
    html = _html_page(refresh_seconds)

    class Handler(BaseHTTPRequestHandler):
        def _send_json(self, payload: Dict[str, Any], status: int = 200):
            body = json.dumps(payload).encode("utf-8")
            self.send_response(status)
            self.send_header("Content-Type", "application/json")
            self.send_header("Content-Length", str(len(body)))
            self.end_headers()
            self.wfile.write(body)

        def _send_html(self, text: str):
            body = text.encode("utf-8")
            self.send_response(200)
            self.send_header("Content-Type", "text/html; charset=utf-8")
            self.send_header("Content-Length", str(len(body)))
            self.end_headers()
            self.wfile.write(body)

        def do_GET(self):
            parsed = urlparse(self.path)
            if parsed.path == "/":
                self._send_html(html)
                return
            if parsed.path == "/api/auth/check":
                query = parse_qs(parsed.query)
                phone_id = query.get("phone_id", [""])[0]
                token = query.get("token", [""])[0]
                valid = auth.validate_session(phone_id, token) if phone_id and token else False
                user = auth.get_user(phone_id) if valid else None
                self._send_json({
                    "valid": valid,
                    "user": {"phone_id": user.phone_id, "name": user.name, "role": user.role} if user else None
                })
                return
            # Protected endpoints below
            query = parse_qs(parsed.query)
            phone_id = self.headers.get("X-Phone-Id", "") or query.get("phone_id", [""])[0]
            token = self.headers.get("X-Session-Token", "") or query.get("token", [""])[0]
            if not auth.validate_session(phone_id, token):
                self._send_json({"error": "unauthorized"}, status=401)
                return
            if parsed.path == "/api/status":
                self._send_json(service.status())
                return
            if parsed.path == "/api/plan":
                max_targets = int(query.get("max", ["5"])[0])
                self._send_json({"plan": service.plan(max_targets=max_targets)})
                return
            if parsed.path == "/api/forecast":
                days = int(query.get("days", ["14"])[0])
                self._send_json({"forecast": service.forecast(days=days)})
                return
            if parsed.path == "/api/forecast-links":
                self._send_json({"links": service.forecast_links()})
                return
            if parsed.path == "/api/events":
                days = int(query.get("days", ["30"])[0])
                self._send_json(service.expected_events(days=days))
                return
            self._send_json({"error": "not found"}, status=404)

        def do_POST(self):
            parsed = urlparse(self.path)
            if parsed.path == "/api/auth/login":
                length = int(self.headers.get("Content-Length", "0"))
                raw = self.rfile.read(length) if length else b"{}"
                try:
                    data = json.loads(raw)
                except json.JSONDecodeError:
                    data = {}
                phone_id = data.get("phone_id", "")
                secret = data.get("secret", "")
                token = auth.authenticate(phone_id, secret)
                user = auth.get_user(phone_id) if token else None
                if token:
                    self._send_json({
                        "token": token,
                        "user": {"phone_id": user.phone_id, "name": user.name, "role": user.role} if user else None
                    })
                else:
                    self._send_json({"error": "invalid credentials"}, status=401)
                return
            self._send_json({"error": "not found"}, status=404)

        def log_message(self, fmt: str, *args):
            logger.info("web %s", fmt % args)

    server = ThreadingHTTPServer((host, port), Handler)
    lan_ip = _best_lan_ip()
    local_url = f"http://127.0.0.1:{port}"
    lan_url = f"http://{lan_ip}:{port}"

    print(f"Dashboard running at: {local_url}")
    if host == "0.0.0.0":
        print(f"Phone URL (same Wi-Fi): {lan_url}")
        try:
            import qrcode

            print("\nScan this QR from your phone:\n")
            qr = qrcode.QRCode(border=1)
            qr.add_data(lan_url)
            qr.make(fit=True)
            qr.print_ascii(invert=True)
            print("")
        except Exception:
            print("Install optional 'qrcode' package to print terminal QR automatically.")
            print(f"Open this URL on phone: {lan_url}")

    print(f"Admin phone IDs: [REDACTED_PHONE], [REDACTED_PHONE]")
    print("Press Ctrl+C to stop.")
    try:
        server.serve_forever()
    except KeyboardInterrupt:
        pass
    finally:
        server.server_close()
